    for line in lines:
        if "Sender (untrusted metadata)" in line:
            in_meta = True
            continue
        if in_meta:
            if line.strip().startswith("```json"):
                continue
            if line.strip().startswith("```"):
                in_meta = False
                continue
            if '"label"' in line or '"id"' in line or line.strip() == "}":
                continue
            continue
